import{f as r,o as t,c as a,a7 as s}from"./chunks/framework.DDLK82Pw.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"S6-Go/阶段08-数据库与消息队列深度.md","filePath":"S6-Go/阶段08-数据库与消息队列深度.md","lastUpdated":1780660866000}'),n={name:"S6-Go/阶段08-数据库与消息队列深度.md"};function e(l,o,i,g,d,c){return t(),a("div",null,[...o[0]||(o[0]=[s('<h2 id="🗄️-阶段八-数据库与消息队列深度" tabindex="-1">🗄️ 阶段八：数据库与消息队列深度 <a class="header-anchor" href="#🗄️-阶段八-数据库与消息队列深度" aria-label="Permalink to &quot;🗄️ 阶段八：数据库与消息队列深度&quot;">​</a></h2><h3 id="_8-1-mysql-进阶" tabindex="-1">8.1 MySQL 进阶 <a class="header-anchor" href="#_8-1-mysql-进阶" aria-label="Permalink to &quot;8.1 MySQL 进阶&quot;">​</a></h3><h4 id="q37-mysql-索引底层为什么用-b-树而不是-hash-或-b-树" tabindex="-1">Q37: MySQL 索引底层为什么用 B+ 树而不是 Hash 或 B 树？ <a class="header-anchor" href="#q37-mysql-索引底层为什么用-b-树而不是-hash-或-b-树" aria-label="Permalink to &quot;Q37: MySQL 索引底层为什么用 B+ 树而不是 Hash 或 B 树？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥 高频</p><p><strong>考点</strong>：索引结构、范围查询、磁盘 IO。</p><p><strong>💡 记忆关键词</strong>：B+ 树、范围查询、矮胖树、叶子节点链表</p><p><strong>答案要点</strong>：</p><ul><li><strong>对比 Hash</strong>：Hash 仅适合等值查询，不支持范围查询和排序；B+ 树叶子节点通过指针连接，天然支持范围查询。</li><li><strong>对比 B 树</strong>：B 树非叶子节点也存数据，导致单页存储的键值少，树更高，IO 次数多；B+ 树非叶子节点只存索引，树更矮胖，查询更稳定（都在叶子节点）。</li></ul><h4 id="q38-go-中如何处理数据库事务的隔离级别" tabindex="-1">Q38: Go 中如何处理数据库事务的隔离级别？ <a class="header-anchor" href="#q38-go-中如何处理数据库事务的隔离级别" aria-label="Permalink to &quot;Q38: Go 中如何处理数据库事务的隔离级别？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：<code>sql.Tx</code>、ACID、MVCC。</p><p><strong>💡 记忆关键词</strong>：BeginTx、隔离级别、FOR UPDATE、乐观锁</p><p><strong>答案要点</strong>：</p><ul><li>使用 <code>db.BeginTx(ctx, &amp;sql.TxOptions{Isolation: ...})</code> 指定隔离级别。</li><li><strong>默认</strong>：通常是 <code>READ COMMITTED</code> 或 <code>REPEATABLE READ</code>（取决于 DB 配置）。</li><li><strong>实践</strong>：对于资金类操作，使用 <code>SELECT ... FOR UPDATE</code>（悲观锁）或基于版本号/时间戳的乐观锁，配合事务确保一致性。</li></ul><h3 id="_8-2-消息队列-kafka-rabbitmq" tabindex="-1">8.2 消息队列 (Kafka/RabbitMQ) <a class="header-anchor" href="#_8-2-消息队列-kafka-rabbitmq" aria-label="Permalink to &quot;8.2 消息队列 (Kafka/RabbitMQ)&quot;">​</a></h3><h4 id="q39-如何保证消息不丢失-生产端、broker、消费端" tabindex="-1">Q39: 如何保证消息不丢失？（生产端、Broker、消费端） <a class="header-anchor" href="#q39-如何保证消息不丢失-生产端、broker、消费端" aria-label="Permalink to &quot;Q39: 如何保证消息不丢失？（生产端、Broker、消费端）&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥 高频</p><p><strong>考点</strong>：ACK 机制、持久化、幂等性。</p><p><strong>💡 记忆关键词</strong>：Confirm 确认、acks=all 落盘、手动 Ack、死信队列</p><p><strong>答案要点</strong>：</p><ul><li><strong>生产端</strong>：开启 Confirm/Ack 模式，消息发送成功后 Broker 返回确认；失败则重试。</li><li><strong>Broker</strong>：配置多副本同步复制（如 Kafka <code>acks=all</code>），确保数据落盘。</li><li><strong>消费端</strong>：手动提交 Offset，业务逻辑处理成功后再 Ack；若失败则 Nack 并进入死信队列（DLQ）。</li></ul><h4 id="q40-如何处理消息重复消费-幂等性设计" tabindex="-1">Q40: 如何处理消息重复消费（幂等性设计）？ <a class="header-anchor" href="#q40-如何处理消息重复消费-幂等性设计" aria-label="Permalink to &quot;Q40: 如何处理消息重复消费（幂等性设计）？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥 高频</p><p><strong>考点</strong>：唯一键、分布式锁、状态机。</p><p><strong>💡 记忆关键词</strong>：唯一索引、SetNX 判重、状态机、消费端幂等</p><p><strong>答案要点</strong>：</p><ul><li>消息队列无法完全保证不重复（网络抖动可能导致 Ack 丢失），因此<strong>消费端必须实现幂等性</strong>。</li><li><strong>方案</strong>： <ol><li><strong>数据库唯一索引</strong>：插入前检查，利用 DB 唯一约束拦截重复。</li><li><strong>Redis SetNX</strong>：处理前检查 <code>MsgID</code> 是否已处理。</li><li><strong>状态机</strong>：如订单状态只能从 <code>Created</code> -&gt; <code>Paid</code>，重复请求因状态不匹配而忽略。</li></ol></li></ul><hr>',28)])])}const _=r(n,[["render",e]]);export{p as __pageData,_ as default};
